`timescale 1ns/1ps
module tb_scalar_pipe_dev;
 logic clk=0,rst_n=0; always #5 clk=~clk; logic imem_req_valid,imem_req_ready=1,imem_resp_valid,imem_resp_ready; logic [31:0] imem_req_addr,imem_resp_data; logic dmem_req_valid,dmem_req_ready=1,dmem_req_write,dmem_resp_valid=0,dmem_resp_ready; logic [31:0] dmem_req_addr,dmem_req_wdata,dmem_resp_data=0; logic [3:0] dmem_req_wstrb; logic trap_valid; logic [31:0] mepc,mcause,mtvec; logic [63:0] cycle_count,instret_count; logic retire_valid,retire_rd_we,retire_mem_we,retire_trap; logic [31:0] retire_pc,retire_instr,retire_rd_data,retire_mem_addr,retire_mem_data,retire_cause; logic [4:0] retire_rd; logic [3:0] retire_mem_wstrb; logic [63:0] imem_stall_cycles,dmem_stall_cycles,dep_stall_cycles,control_flush_cycles; logic [31:0] mem[0:31]; integer i,n,run,maxrun,last;
 rv32_core_pipe dut(.*);
 always_ff @(posedge clk) begin if(!rst_n) begin imem_resp_valid<=0;n<=0;run<=0;maxrun<=0;last<=-2;end else begin if(imem_resp_valid&&imem_resp_ready)imem_resp_valid<=0; if(imem_req_valid)begin imem_resp_valid<=1;imem_resp_data<=mem[imem_req_addr[6:2]];end if(retire_valid&&!retire_trap)begin n<=n+1;if(cycle_count==last+1)begin run<=run+1;if(run+1>maxrun)maxrun<=run+1;end else begin run<=1;if(maxrun<1)maxrun<=1;end last<=cycle_count;$display("RETIRE cycle=%0d pc=%h",cycle_count,retire_pc);end end end
 function automatic [31:0] a(input integer x,input integer r);a={x[11:0],5'd0,3'd0,r[4:0],7'h13};endfunction
 initial begin for(i=0;i<16;i=i+1)mem[i]=a(i+1,i+1);mem[16]=32'h73;repeat(3)@(posedge clk);rst_n=1;repeat(100)begin @(posedge clk);if(trap_valid)begin $display("PIPE-DEV cycles=%0d retired=%0d maxrun=%0d CPI=%f",cycle_count,n,maxrun,cycle_count*1.0/n);if(n!=16||maxrun<4)$fatal(1,"pipeline failure");$finish;end end $fatal;end
endmodule
